using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Uses constructor injection — the SDK creates a new instance per invocation,
/// resolving HttpClient and ILogger from the DI container automatically.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all items from the API.")]
    public async Task<string> ListItems(CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing all items");
        var json = await httpClient.GetStringAsync("/api/items", cancellationToken);
        return json;
    }

    [McpServerTool, Description("Get a single item by its unique identifier.")]
    public async Task<string> GetItem(
        [Description("The unique identifier of the item to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Getting item {Id}", id);
        var response = await httpClient.GetAsync($"/api/items/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Create a new item with a name and optional description.")]
    public async Task<string> CreateItem(
        [Description("Name for the new item")] string name,
        [Description("Optional description of the item")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating item {Name}", name);

        var payload = JsonSerializer.Serialize(new { name, description }, JsonOptions);
        var content = new StringContent(payload, Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/api/items", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Search for items matching a query string.")]
    public async Task<string> SearchItems(
        [Description("Search query to filter items by name or description")] string query,
        [Description("Maximum number of results to return (1-100)")] int maxResults = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching items with query '{Query}', max {Max}", query, maxResults);
        var url = $"/api/items/search?q={Uri.EscapeDataString(query)}&limit={maxResults}";
        var json = await httpClient.GetStringAsync(url, cancellationToken);
        return json;
    }
}

